 1→'use client';
 2→import React, { useState } from 'react';
 3→import { useRouter } from 'next/navigation';
 4→import { createClient } from '@/lib/supabase/client';
 5→import Link from 'next/link';
 6→import { Loader2 } from 'lucide-react';
 7→
 8→export default function LoginPage() {
 9→  const [email, setEmail] = useState('');
10→  const [password, setPassword] = useState('');
11→  const [loading, setLoading] = useState(false);
12→  const [error, setError] = useState('');
13→  const router = useRouter();
14→  const supabase = createClient();
15→
16→  const handleLogin = async (e: React.FormEvent) => {
17→    e.preventDefault();
18→    setLoading(true);
19→    setError('');
20→
21→    const { error } = await supabase.auth.signInWithPassword({
22→      email,
23→      password,
24→    });
25→
26→    if (error) {
27→      setError(error.message);
28→      setLoading(false);
29→    } else {
30→      router.push('/app');
31→      router.refresh();
32→    }
33→  };
34→
35→  return (
36→    <div className="min-h-screen flex items-center justify-center p-4">
37→      <div className="w-full max-w-md p-8 glass-panel rounded-2xl">
38→        <h1 className="text-2xl font-serif font-bold mb-2 text-center">Connexion</h1>
39→        <p className="text-gray-400 text-center mb-8">Accédez à votre espace CitedBy</p>
40→
41→        {error && <div className="bg-red-500/10 text-red-400 p-3 rounded-lg mb-4 text-sm">{error}</div>}
42→
43→        <form onSubmit={handleLogin} className="space-y-4">
44→          <div>
45→            <label className="block text-sm font-medium mb-1">Email</label>
46→            <input
47→              type="email"
48→              value={email}
49→              onChange={(e) => setEmail(e.target.value)}
50→              className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-primary/50 outline-none"
51→              required
52→            />
53→          </div>
54→          <div>
55→            <label className="block text-sm font-medium mb-1">Mot de passe</label>
56→            <input
57→              type="password"
58→              value={password}
59→              onChange={(e) => setPassword(e.target.value)}
60→              className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-primary/50 outline-none"
61→              required
62→            />
63→          </div>
64→          <button
65→            type="submit"
66→            disabled={loading}
67→            className="w-full bg-primary text-black font-bold py-3 rounded-lg hover:bg-emerald-600 transition-colors flex items-center justify-center"
68→          >
69→            {loading ? <Loader2 className="animate-spin" /> : 'Se connecter'}
70→          </button>
71→        </form>
72→        <p className="mt-6 text-center text-sm text-gray-500">
73→          Pas encore de compte ? <Link href="/register" className="text-primary hover:underline">S'inscrire</Link>
74→        </p>
75→      </div>
76→    </div>
77→  );
78→}

