 54→    agency: { label: "Agency", variant: "warning" },
 55→  };
 56→
 57→  const currentPlan = planBadge[workspace?.plan || "starter"] || planBadge.starter;
 58→
 59→  const isActive = (href: string) => {
 60→    if (href === "/app") return pathname === "/app";
 61→    return pathname.startsWith(href);
