 95→            )}
 96→          >
 97→            <item.icon size={18} />
 98→            {item.label}
 99→          </Link>
100→        ))}
101→
102→        <div className="my-3 border-t border-white/5" />
103→
104→        {BOTTOM_ITEMS.map((item) => (
105→          <Link
106→            key={item.href}
107→            href={item.href}
108→            onClick={() => setMobileOpen(false)}
109→            className={cn(
110→              "flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-colors",
111→              isActive(item.href)
112→                ? "bg-primary/10 text-primary"
113→                : "text-white/50 hover:text-white hover:bg-white/5"
114→            )}
115→          >
116→            <item.icon size={18} />
117→            {item.label}
118→          </Link>
119→        ))}
120→      </nav>
121→
122→      {/* User Section */}
123→      <div className="p-4 border-t border-white/10">
124→        <div className="flex items-center gap-3 px-2 py-2">
125→          <Avatar fallback={user.email} size="sm" />
126→          <div className="flex-1 min-w-0">
127→            <p className="text-sm font-medium text-white truncate">{user.email}</p>
128→            <Badge variant={currentPlan.variant} className="mt-0.5">
129→              {currentPlan.label}
130→            </Badge>
131→          </div>
132→          <ThemeToggle />
133→          <NotificationBell />
134→        </div>
135→        <form action="/auth/signout" method="post">
