150→        aria-label={mobileOpen ? "Fermer le menu" : "Ouvrir le menu"}
151→        aria-expanded={mobileOpen}
152→      >
153→        {mobileOpen ? <X size={20} aria-hidden="true" /> : <Menu size={20} aria-hidden="true" />}
154→      </button>
155→
156→      {/* Mobile overlay */}
157→      {mobileOpen && (
158→        <div
159→          className="fixed inset-0 bg-black/60 z-40 md:hidden"
160→          onClick={() => setMobileOpen(false)}
161→        />
162→      )}
163→
164→      {/* Sidebar */}
165→      <aside
166→        className={cn(
167→          "w-64 border-r border-white/10 bg-[#0d0f12] flex flex-col sticky top-0 h-screen z-40 transition-transform",
168→          "md:translate-x-0",
