 7→import { cn } from "@/lib/utils";
 8→
 9→export default function ProjectLayout({
10→  children,
11→  params
12→}: {
13→  children: React.ReactNode;
14→  params: { id: string };
15→}) {
16→  const pathname = usePathname();
17→  const baseUrl = `/app/projects/${params.id}`;
18→
19→  const tabs = [
20→    { label: "Vue d'ensemble", href: `${baseUrl}/overview` },
21→    { label: "Visibilité IA", href: `${baseUrl}/ai-visibility` },
22→    { label: "Citations", href: `${baseUrl}/citations` },
23→    { label: "Recommandations", href: `${baseUrl}/recommendations` },
