  1→"use client";
  2→
  3→import { useState } from "react";
  4→import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
  5→import { Badge } from "@/components/ui/badge";
  6→import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
  7→import { EmptyState } from "@/components/ui/empty-state";
  8→import { Button } from "@/components/ui/button";
  9→import { Eye, TrendingUp, TrendingDown, Minus, Play, Bot } from "lucide-react";
 10→
 11→interface EngineVisibility {
 12→  engine: string;
 13→  score: number;
 14→  trend: number;
 15→  mentions: number;
 16→  lastChecked: string;
 17→}
 18→
 19→// Mock data — will come from Supabase run_results
 20→const MOCK_VISIBILITY: EngineVisibility[] = [
 21→  { engine: "ChatGPT", score: 72, trend: 8, mentions: 15, lastChecked: "Il y a 2h" },
 22→  { engine: "Perplexity", score: 58, trend: -3, mentions: 8, lastChecked: "Il y a 2h" },
 23→  { engine: "Gemini", score: 45, trend: 12, mentions: 5, lastChecked: "Il y a 2h" },
 24→  { engine: "Claude", score: 61, trend: 5, mentions: 10, lastChecked: "Il y a 2h" },
 25→  { engine: "Copilot", score: 33, trend: 0, mentions: 2, lastChecked: "Il y a 2h" },
 26→];
 27→
 28→function ScoreColor({ score }: { score: number }) {
 29→  if (score >= 70) return <span className="text-emerald-400">{score}</span>;
 30→  if (score >= 50) return <span className="text-amber-400">{score}</span>;
 31→  return <span className="text-red-400">{score}</span>;
 32→}
 33→
 34→function TrendIndicator({ value }: { value: number }) {
 35→  if (value > 0) return <span className="text-emerald-400 text-xs flex items-center gap-0.5"><TrendingUp size={12} /> +{value}%</span>;
 36→  if (value < 0) return <span className="text-red-400 text-xs flex items-center gap-0.5"><TrendingDown size={12} /> {value}%</span>;
 37→  return <span className="text-white/30 text-xs flex items-center gap-0.5"><Minus size={12} /> 0%</span>;
 38→}
 39→
 40→export default function AIVisibilityPage() {
 41→  const [tab, setTab] = useState("overview");
 42→
 43→  const avgScore = Math.round(MOCK_VISIBILITY.reduce((s, v) => s + v.score, 0) / MOCK_VISIBILITY.length);
 44→
 45→  return (
 46→    <div>
 47→      <div className="flex justify-between items-center mb-8">
 48→        <h2 className="text-2xl font-serif font-bold text-white">Visibilite IA</h2>
 49→        <Button>
 50→          <Play size={16} /> Lancer un scan
 51→        </Button>
 52→      </div>
 53→
 54→      {/* Summary Cards */}
 55→      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
 56→        <Card className="p-5">
 57→          <p className="text-xs text-white/40 uppercase mb-1">Score global</p>
 58→          <p className="text-3xl font-bold"><ScoreColor score={avgScore} /><span className="text-sm text-white/30">/100</span></p>
 59→        </Card>
 60→        <Card className="p-5">
 61→          <p className="text-xs text-white/40 uppercase mb-1">Moteurs IA</p>
 62→          <p className="text-3xl font-bold text-white">{MOCK_VISIBILITY.length}</p>
 63→        </Card>
 64→        <Card className="p-5">
 65→          <p className="text-xs text-white/40 uppercase mb-1">Mentions totales</p>
 66→          <p className="text-3xl font-bold text-white">{MOCK_VISIBILITY.reduce((s, v) => s + v.mentions, 0)}</p>
 67→        </Card>
 68→        <Card className="p-5">
 69→          <p className="text-xs text-white/40 uppercase mb-1">Tendance</p>
 70→          <div className="mt-1"><TrendIndicator value={Math.round(MOCK_VISIBILITY.reduce((s, v) => s + v.trend, 0) / MOCK_VISIBILITY.length)} /></div>
 71→        </Card>
 72→      </div>
 73→
 74→      {/* Engine Breakdown */}
 75→      <Card>
 76→        <CardHeader>
 77→          <CardTitle className="flex items-center gap-2">
 78→            <Bot size={18} className="text-primary" />
 79→            Visibilite par moteur IA
 80→          </CardTitle>
 81→        </CardHeader>
 82→        <CardContent>
 83→          <div className="space-y-1">
 84→            {MOCK_VISIBILITY.map((engine) => (
 85→              <div key={engine.engine} className="flex items-center justify-between py-3 px-3 rounded-xl hover:bg-white/5 transition-colors">
 86→                <div className="flex items-center gap-4">
 87→                  <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center text-xs font-bold text-white/60">
 88→                    {engine.engine.substring(0, 2)}
 89→                  </div>
